    19→
    20→GrpcSubscriptionImpl::GrpcSubscriptionImpl(GrpcMuxSharedPtr grpc_mux,
    21→                                           SubscriptionCallbacks& callbacks,
    22→                                           OpaqueResourceDecoderSharedPtr resource_decoder,
    23→                                           SubscriptionStats stats, absl::string_view type_url,
    24→                                           Event::Dispatcher& dispatcher,
    25→                                           std::chrono::milliseconds init_fetch_timeout,
    26→                                           bool is_aggregated, const SubscriptionOptions& options)
    27→    : grpc_mux_(grpc_mux), callbacks_(callbacks), resource_decoder_(resource_decoder),
    28→      stats_(stats), type_url_(type_url), dispatcher_(dispatcher),
    29→      init_fetch_timeout_(init_fetch_timeout), is_aggregated_(is_aggregated), options_(options) {}
    30→
    31→// Config::Subscription
    32→void GrpcSubscriptionImpl::start(const absl::flat_hash_set<std::string>& resources) {
    33→  if (init_fetch_timeout_.count() > 0) {
    34→    init_fetch_timeout_timer_ = dispatcher_.createTimer([this]() -> void {
    35→      onConfigUpdateFailed(Envoy::Config::ConfigUpdateFailureReason::FetchTimedout, nullptr);
    36→    });
    37→    init_fetch_timeout_timer_->enableTimer(init_fetch_timeout_);
    38→  }
    39→
    40→  watch_ = grpc_mux_->addWatch(type_url_, resources, *this, resource_decoder_, options_);
    41→
    42→  // The attempt stat here is maintained for the purposes of having consistency between ADS and
    43→  // gRPC/filesystem/REST Subscriptions. Since ADS is push based and muxed, the notion of an
    44→  // "attempt" for a given xDS API combined by ADS is not really that meaningful.
    45→  stats_.update_attempt_.inc();
    46→
    47→  // ADS initial request batching relies on the users of the GrpcMux *not* calling start on it,
    48→  // whereas non-ADS xDS users must call it themselves.
    49→  if (!is_aggregated_) {
    50→    grpc_mux_->start();
    51→  }
    52→}
    53→
    54→void GrpcSubscriptionImpl::updateResourceInterest(
    55→    const absl::flat_hash_set<std::string>& update_to_these_names) {
    56→  watch_->update(update_to_these_names);
    57→  stats_.update_attempt_.inc();
    58→}
    59→
    60→void GrpcSubscriptionImpl::requestOnDemandUpdate(
    61→    const absl::flat_hash_set<std::string>& for_update) {
    62→  grpc_mux_->requestOnDemandUpdate(type_url_, for_update);
    63→  stats_.update_attempt_.inc();
    64→}
    65→
    66→// Config::SubscriptionCallbacks
    67→absl::Status
    68→GrpcSubscriptionImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& resources,
    69→                                     const std::string& version_info) {
    70→  disableInitFetchTimeoutTimer();
    71→  // TODO(mattklein123): In the future if we start tracking per-resource versions, we need to
    72→  // supply those versions to onConfigUpdate() along with the xDS response ("system")
    73→  // version_info. This way, both types of versions can be tracked and exposed for debugging by
    74→  // the configuration update targets.
    75→  auto start = dispatcher_.timeSource().monotonicTime();
    76→  absl::Status status = callbacks_.onConfigUpdate(resources, version_info);
    77→  if (!status.ok()) {
    78→    return status;
    79→  }
    80→  std::chrono::milliseconds update_duration = std::chrono::duration_cast<std::chrono::milliseconds>(
    81→      dispatcher_.timeSource().monotonicTime() - start);
    82→  stats_.update_success_.inc();
    83→  stats_.update_attempt_.inc();
    84→  stats_.update_time_.set(DateUtil::nowToMilliseconds(dispatcher_.timeSource()));
    85→  stats_.version_.set(HashUtil::xxHash64(version_info));
    86→  stats_.version_text_.set(version_info);
    87→  stats_.update_duration_.recordValue(update_duration.count());
    88→  ENVOY_LOG(debug, "gRPC config for {} accepted with {} resources with version {}", type_url_,
    89→            resources.size(), version_info);
    90→
    91→  if (update_duration > UpdateDurationLogThreshold) {
    92→    ENVOY_LOG(debug, "gRPC config update took {} ms! Resources names: {}", update_duration.count(),
    93→              absl::StrJoin(resources, ",", ResourceNameFormatter()));
    94→  }
    95→  return absl::OkStatus();
    96→}
